  cin.tie(0);
  int n;
  cin >> n;
  for (int i = 1; i < n + 1; i++) {
    int x;
    cin >> x;
    x--;
    if (x == -1) continue;
    del[x].push_back(i - 1);
    del[i - 1].push_back(x);
  }
  if (dfs(0) == 1) {
    cout << "NO";
  } else {
    cout << "YES\n";
    tarjan(n);
    reverse(components.begin(), components.end());
    for (vector<int> comp : components) {
      cout << comp[0] + 1 << endl;
    }
    tarjan(n);
  }
}

