  for (int i = 1; i <= s; i++) {
    if (!used[i]) {
      if (best_goal[i] > 0) ans += best_goal[i];
    } else {
      id[i] = ++cnt;
    }
  }
  int st = 0, ed = cnt + 1;
  cnt = 0;
  for (int i = 1; i <= s; i++) {
    if (used[i]) {
      if (best_goal[i] >= 0)
        ans += best_goal[i], D.addedge(st, id[i], best_goal[i]);
      else
        D.addedge(id[i], ed, -best_goal[i]);
      for (auto& u : g[i]) D.addedge(id[i], id[u], INF_CAP);
    }
  }
